Trigger.script:
if Legacy.Settings.Basher.goldtrack == false then return end local str = matches[2]..", "..matches[3] local name_table = string.split(str, ", ")
Legacy.Settings.Basher.Group = Legacy.Settings.Basher.Group or {}
--Add remainder of group when following a leader for _,v in pairs(name_table) do if Legacy.Settings.Basher.Group[v:title()] == nil then Legacy.Settings.Basher.Group[v:title()] = 0 end end

deleteFull()
Legacy.Settings.Basher.frenemies = Legacy.Settings.Basher.frenemies or {}

table.insert(Legacy.Settings.Basher.frenemies, "<gold>"..matches[2].." is also attacking you!")

deleteFull() local aff = matches[2]:lower() cecho("\n<white>[<gold>Predicted<white>]: <green>"..matches[2]:upper()) Legacy.Settings.Basher.Predictions = Legacy.Settings.Basher.Predictions or {}
Legacy.Settings.Basher.Predictions[aff:lower()] = true
tempTimer(10, function() Legacy.Settings.Basher.Predictions[aff:lower()] = false end)
